fun solve(edges: Array<Array<Long>>, online: Array<Boolean>, k: Long): Long {
    val n = online.size
    val adj = Array(n) { mutableListOf<Pair<Long, Long>>() }
    val inDegree = LongArray(n) { 0L }

    for (edge in edges) {
        val u = edge[0].toInt()
        val v = edge[1].toInt()
        val cost = edge[2]
        adj[u].add(Pair(v.toLong(), cost))
        inDegree[v] += 1
    }

    val queue = LinkedList<Int>()
    for (i in 0 until n) {
        if (inDegree[i] == 0L) {
            queue.add(i)
        }
    }

    val topologicalOrder = mutableListOf<Int>()
    while (queue.isNotEmpty()) {
        val u = queue.pollFirst()
        topologicalOrder.add(u)
        for ((v, cost) in adj[u]) {
            inDegree[v] -= 1
            if (inDegree[v] == 0L) {
                queue.add(v.toInt())
            }
        }
    }

    var maxEdge = 0L
    for (edge in edges) {
        maxEdge = max(maxEdge, edge[2])
    }

    var low = 0L
    var high = maxEdge
    var answer = -1L

    fun check(mid: Long): Boolean {
        val dp = LongArray(n) { Long.MAX_VALUE }
        dp[0] = 0L
        for (u in topologicalOrder) {
            if (!online[u.toInt()]) continue
            for ((v, cost) in adj[u.toInt()]) {
                if (cost < mid) continue
                if (!online[v.toInt()]) continue
                if (dp[u] + cost < dp[v]) {
                    dp[v] = dp[u] + cost
                }
            }
        }
        return dp[n - 1] <= k
    }

    while (low <= high) {
        val mid = (low + high) / 2
        if (check(mid)) {
            answer = mid
            low = mid + 1
        } else {
            high = mid - 1
        }
    }

    return answer
}
