fun solve(edges: Array<Array<Long>>, online: Array<Boolean>, k: Long): Long {
    val n = online.size
    val adj = Array(n) { mutableListOf<Pair<Long, Long>>() }
    for (edge in edges) {
        val u = edge[0]
        val v = edge[1]
        val cost = edge[2]
        adj[u.toInt()].add(Pair(v, cost))
    }

    val dp = LongArray(n) { -Long.MAX_VALUE }
    dp[0] = Long.MAX_VALUE

    val pq = PriorityQueue<Triple<Long, Long, Long>> { a, b ->
        val a1 = a.first
        val b1 = b.first
        if (a1 < b1) -1
        else if (a1 > b1) 1
        else 0
    }

    pq.add(Triple(-Long.MAX_VALUE, 0L, 0L))

    while (pq.isNotEmpty()) {
        val (negCurrentMin, totalCost, u) = pq.poll()
        val currentMin = -negCurrentMin

        if (u == n - 1L) {
            return currentMin
        }

        if (currentMin < dp[u.toInt()]) {
            continue
        }

        for (edge in adj[u.toInt()]) {
            val v = edge.first
            val cost = edge.second

            if (!online[v.toInt()]) {
                continue
            }

            val newMin = min(currentMin, cost)
            val newTotal = totalCost + cost

            if (newTotal > k) {
                continue
            }

            if (newMin > dp[v.toInt()]) {
                dp[v.toInt()] = newMin
                pq.add(Triple(-newMin, newTotal, v))
            }
        }
    }

    return -1L
}
